def test_multiline_glosses_and_words_are_applied_correctly(clean_mets_book):
    """
    Tests that multi-line glosses with words are correctly applied to a clean TEI file.
    """
    page = clean_mets_book[0]

    # build connection cycle
    connections = quick_build_chain(page, [
        "eSc_line_a2269548",
        "eSc_line_51d77c47",
        "eSc_line_58a219fc",
        "eSc_line_c50a8fcb",
        "eSc_line_da20b4de",
        "eSc_line_ae063059",
        "eSc_line_d90e3870",
        "eSc_line_338f6933",
        "eSc_line_3dc3ee51",
        "eSc_line_b9413214",
    ])
    connections.append(ConnectedPair(page.get_object_from_id("eSc_line_b9413214"),
                               Word(line=page.get_object_from_id("eSc_line_6545c663"), word_idx=5)))
    chain = [connections]

    # apply connections to page -> TEI
    connector = GlossOnPageConnector(page)
    tei = connector.apply_connections(chain)
    
