def test_single_line_glosses_are_applied_correctly(clean_mets_book):
    """
    Tests that single-line glosses with a connection to a word is correctly applied to a clean TEI file.
    """
    page = clean_mets_book[0]

    connections = [ConnectedPair(page.get_object_from_id("eSc_line_d2c801de"),
                               Word(line=page.get_object_from_id("eSc_line_6545c663"), word_idx=5))]
    chain = [connections]

    # apply connections to page -> TEI
    connector = GlossOnPageConnector(page)
    tei = connector.apply_connections(chain)

