def test_cleaned_xml_is_same_as_untouched_xml(clean_mets_book):
    """
    Tests that the removal of connection information (xml:id, connection chains) can correctly be removed from
    a file to which connection information has been applied. This means that the cleaned TEI and the original
    TEI contain the same information.

    This is important, because when we want to change the existing connections in a TEI file or add new ones
    to it, we must apply them to a clean TEI such that the new connection information and the already present
    information (like xml:id and connection chains) do not interfere.
    """
    page = clean_mets_book[0]

    # build connection cycle
    connections = quick_build_chain(page, [
        "eSc_line_a2269548",
        "eSc_line_51d77c47",
        "eSc_line_58a219fc",
        "eSc_line_c50a8fcb",
        "eSc_line_da20b4de",
        "eSc_line_ae063059",
        "eSc_line_d90e3870",
        "eSc_line_338f6933",
        "eSc_line_3dc3ee51",
        "eSc_line_b9413214",
        "eSc_line_1c990ac5",  # ref
        "eSc_line_d2c801de",  # ref
    ])
    connections.append(ConnectedPair(page.get_object_from_id("eSc_line_d2c801de"),
                               Word(line=page.get_object_from_id("eSc_line_6545c663"), word_idx=5)))
    chain = [connections]

    # apply connections to page -> TEI
    connector = GlossOnPageConnector(page)
    modified_page = copy.deepcopy(page)
    modified_page.tei = connector.apply_connections(chain)

    # Load newly created TEI into connector to retrieve the cleaned XML (i.e. all connection information is discarded)
    new_connector = GlossOnPageConnector(modified_page)

    # Check that original clean TEI and the cleaned-up TEI match
    assert(str(page.tei) == str(new_connector.clean_tei))